const champion = $('GET Champion').first().json || {};
const scoresResp = $('GET Eval Scores').first().json || {};
const lineage = $('GET Lineage').first().json || {};
const gpu = $input.first().json || {};

const trends = Array.isArray(scoresResp)
  ? scoresResp
  : Array.isArray(scoresResp.trends)
  ? scoresResp.trends
  : Array.isArray(scoresResp.scores)
  ? scoresResp.scores
  : [];
const nodes = Array.isArray(lineage.nodes) ? lineage.nodes : [];

const now = new Date();
const since = new Date(now.getTime() - 24 * 3600 * 1000);
const recent = nodes.filter((n) => {
  const ts = n.created_at || n.completed_at || n.timestamp;
  if (!ts) return false;
  const t = new Date(ts);
  return Number.isFinite(t.valueOf()) && t >= since;
});

let promoted24h = 0;
let discarded24h = 0;
for (const n of recent) {
  const decision = String(n.decision || (n.promoted ? 'promote' : 'discard')).toLowerCase();
  if (decision === 'promote') promoted24h += 1;
  else if (decision === 'discard') discarded24h += 1;
}
const total24h = promoted24h + discarded24h;

// Champion scores per benchmark — try champion.scores or latest promoted gen.
let champScores = champion.scores || champion.benchmark_scores || {};
if (!champScores || Object.keys(champScores).length === 0) {
  const promotedTrends = trends.filter((t) => t.promoted);
  if (promotedTrends.length) {
    const maxGen = Math.max(...promotedTrends.map((t) => Number(t.generation) || 0));
    champScores = {};
    for (const t of promotedTrends.filter((t) => Number(t.generation) === maxGen)) {
      champScores[t.benchmark] = Number(t.score ?? t.child_score ?? 0);
    }
  }
}
const champEntries = Object.entries(champScores).filter(([, v]) => Number.isFinite(Number(v)));
const champAvg = champEntries.length
  ? champEntries.reduce((a, [, v]) => a + Number(v), 0) / champEntries.length
  : (Number(champion.avg_score) || null);
let weakest = null;
for (const [k, v] of champEntries) {
  if (!weakest || Number(v) < weakest.score) weakest = { benchmark: k, score: Number(v) };
}

// Trend classification — last 5 promoted gen averages.
const promotedByGen = {};
for (const t of trends) {
  if (!t || !t.promoted) continue;
  const gen = Number(t.generation);
  if (!Number.isFinite(gen)) continue;
  if (!promotedByGen[gen]) promotedByGen[gen] = [];
  promotedByGen[gen].push(Number(t.score ?? t.child_score ?? 0));
}
const genAvgs = Object.entries(promotedByGen)
  .map(([g, arr]) => ({ gen: Number(g), avg: arr.reduce((a, b) => a + b, 0) / arr.length }))
  .sort((a, b) => b.gen - a.gen)
  .slice(0, 5);
let trend = 'unknown';
if (genAvgs.length >= 3) {
  const delta = genAvgs[0].avg - genAvgs[Math.min(2, genAvgs.length - 1)].avg;
  if (delta > 0.005) trend = 'improving';
  else if (delta < -0.005) trend = 'regressing';
  else trend = 'plateau';
}

const adapterCount = nodes.length || promoted24h;
const storageGb = (adapterCount * 0.5).toFixed(1);

const gpuTemp = gpu.temperature ?? 'n/a';
const gpuUtil = gpu.gpu_utilization ?? gpu.utilization ?? 'n/a';
const gpuMemUsed = gpu.memory_used ?? 'n/a';
const gpuMemTotal = gpu.memory_total ?? 'n/a';

let recommendation = 'Keep evolving.';
if (trend === 'plateau') recommendation = 'Plateau detected — increase training data or change LoRA rank/lr.';
else if (trend === 'regressing') recommendation = 'Regression — review weak categories and consider rolling back.';
if (adapterCount > 80) recommendation += ' Disk cleanup likely needed.';

const date = now.toISOString().slice(0, 10);
const championLabel = champion.model_id || champion.champion_model_id || 'unknown';
const championGen = champion.generation ?? champion.gen ?? 'n/a';

const report = [
  `:bar_chart: *ModelForge Daily Report* — ${date}`,
  '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501',
  `:trophy: Champion: \`${championLabel}\` (gen ${championGen}, avg ${champAvg !== null ? champAvg.toFixed(4) : 'n/a'})`,
  `:chart_with_upwards_trend: Trend: *${trend}*`,
  `:wrench: 24h: ${total24h} generations (${promoted24h} promoted / ${discarded24h} discarded)`,
  `:dart: Weakest benchmark: \`${weakest ? weakest.benchmark : 'n/a'}\` (${weakest ? weakest.score.toFixed(4) : 'n/a'})`,
  `:floppy_disk: Storage: ${adapterCount} lineage nodes (~${storageGb} GB est.)`,
  `:thermometer: GPU: ${gpuTemp}\u00b0C, util ${gpuUtil}%, mem ${gpuMemUsed}/${gpuMemTotal}`,
  '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501',
  `:bulb: Recommendation: ${recommendation}`,
].join('\n');

console.log('[daily-report]', { date, trend, total24h, promoted24h, discarded24h });

return [{
  json: {
    date,
    champion_model_id: championLabel,
    champion_generation: championGen,
    champion_avg: champAvg,
    trend,
    total_24h: total24h,
    promoted_24h: promoted24h,
    discarded_24h: discarded24h,
    weakest,
    adapter_count: adapterCount,
    storage_gb: storageGb,
    gpu_temp: gpuTemp,
    gpu_util: gpuUtil,
    gpu_mem_used: gpuMemUsed,
    gpu_mem_total: gpuMemTotal,
    recommendation,
    slack_message: report,
  }
}];
